from flask import Flask, request
from kafka import KafkaProducer
import json

app = Flask(__name__)
producer = None  # Initialize producer here to avoid race conditions when multiple consumers read the same topic.

def init_producer():
    global producer   # pylint: disable=global-statement,unused-variable
    producer = KafkaProducer(bootstrap_servers='localhost')    

@app.route('/publish', methods=['POST'])  # Define route handler for POST request on /publish endpoint with topic name as parameter in the body of post data (e.g., {"topic":"myTopic", "message":{"key1": "value1","key2" : "value2"} } )
def publish_to_kafka():  # pylint: disable=unused-variable, redefined-builtin
    message = request.json['message']   # Get the posted data and convert to json format using 'request' object in Flask application (Flask provides a way of getting http requests)
    
    topic_name =  str(request.args.get('topic'))  # Parse URL argument that is expected as post request parameter, ie: /publish?topic=myTopic   and convert to string using 'str' function in python built-in library (convert a value of one type into another)
    
    if not producer or topic_name != str(producer.bootstrap_servers[-1]):  # If no existing Producer OR Topics have changed, reinitialize the connection with Kafka bootstrap servers   then send message to provided topics: myTopic (from HTTP request parameters)
        init_producer()   
        
    producer.send(topic_name, json.dumps(message).encode('utf-8'))  # Use 'json' for conversion of python data types into JSON format and encoding the message to bytes so it can be sent over network by Kafka Producer   (produce a record with topic name as "myTopic" using kafka producer)
    
    return {"status": True}  # Return successful HTTP response. Can also include error messages if required, or other useful information such the message was successfully published to this particular server/topic etc.. by KAFKA in our case   (HTTP request status). We can use Flask's built-in http responses for easier handling of these tasks